{!REQUIRESCRIPT("/soap/ajax/38.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/38.0/apex.js")} 

function getErrorMessages(results) {
	var messages = [];
	for (var i = 0; i < results.length; i++) {
	  var r = results[i];
	  if (!r.getBoolean("success")) {
	    messages = messages.concat(getMessagesOfAResult(r));
	  }
	}
	return messages;

}

function getMessagesOfAResult(res) {
	var messages = [];
	var errors = res.getArray("errors");
	for (var i = 0; i < errors.length; i++) {
	  e = errors[i];
	  messages.push(e.message);
	}
	return messages;
}

var records = {!GETRECORDIDS($ObjectType.Sansan_CI__BizCard__c)}; 

if (records.length < 1 ) { 
    alert('1つ以上名刺を選択してください');
} else { 
    var result = window.confirm('選択した名刺を振分け対象外にします。');
    if( result ) {
	    var objs = [];
	    for (var i = 0; i < records.length; i++) {
	        var obj = new sforce.SObject('BizCard__c');
	        obj.id = records[i];
	        obj.IsNotDistribution__c = "true";
	        objs.push(obj);
	    }
	    var updateResults = sforce.connection.update(objs);

	    var messages = getErrorMessages(updateResults);

	    if (messages.length > 0) {
		  var message = "";
	      for (var i = 0; i < messages.length; i++) {
	      	message = message + messages[i];
	      }
	      alert(messages.join("\n"));
	    }else{
		    location.href='/' + records[0].substring(0,3);
		}

    }
}
